#include <vector>
#include <stack>

std::vector<int> mostCompetitive(std::vector<int>& nums, int k) {
    std::stack<int> stk;
    int n = nums.size();
    for (int i = 0; i < n; i++) {
        while (!stk.empty() && stk.top() > nums[i] && stk.size() + n - i > k) {
            stk.pop();
        }
        if (stk.size() < k) {
            stk.push(nums[i]);
        }
    }
    std::vector<int> result(k);
    for (int i = k - 1; i >= 0; i--) {
        result[i] = stk.top();
