int countBinarySubstrings(string s) {
    int prev = 0, curr = 1, result = 0;
    for (int i = 1; i < s.length(); i++) {
        if (s[i] == s[i - 1]) {
            curr++;
        } else {
            result += min(prev, curr);
            prev = curr;
            curr = 1;
        }
    }
    return result + min(prev, curr);
}
```

