vector<int> findBall(vector<vector<int>>& grid) {
    int m = grid.size();
    int n = grid[0].size();
    vector<int> result(n, -1);

    for (int i = 0; i < n; i++) {
        int x = 0, y = i;

        while (x < m) {
            int nx = x + 1, ny = y + grid[x][y];
            if (ny < 0 || ny >= n || grid[x][ny] != grid[x][y]) break;
            x = nx;
            y = ny;
        }

        if (x == m) {
            result[i] = y;
        }
    }

    return result;
}
```

