#include <queue>
#include <vector>

int maxDistance(std::vector<std::vector<int>>& grid) {
    int distance = -1;
    std::queue<std::pair<int, int>> waterCells;
    int n = grid.size();

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] == 1) {
                waterCells.push({i, j});
            }
        }
    }

    if (waterCells.size() == 0 || waterCells.size() == n * n) {
        return distance;
    }

    std::vector<std::vector<int>> directions{{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

    while (!waterCells.empty()) {
        int size = waterCells.size();
        while (size--) {
            auto [x, y] = waterCells.front();
            waterCells.pop();

            for (const auto& dir : directions) {
                int newX = x + dir[0], newY = y + dir[1];
                if (newX >= 0 && newX < n && newY >= 0 && newY < n && grid[newX][newY] == 0) {
                    grid[newX][newY] = 1;
                    waterCells.push({newX, newY});
                }
            }
        }
        distance++;
    }

    return distance - 1;
}
```

The algorithm uses breadth-first search (BFS) to traverse the grid. We start by initializing a `queue`, named `waterCells`, containing every land cell's coordinates (row and col). Then, we perform a BFS traversal starting from every land cell frontier.

