int min_operations(std::vector<int>& nums) {
    std::priority_queue<int, std::vector<int>, std::less<int>> max_heap(nums.begin(), nums.end());
    int initial_sum = std::accumulate(nums.begin(), nums.end(), 0);
    int target_sum = initial_sum / 2;
    int sum_so_far = 0;
    int operations = 0;

    while (sum_so_far <= target_sum) {
        int largest = max_heap.top();
        max_heap.pop();
        sum_so_far += largest / 2;
        operations += 1;
    }

    return operations;
}
```

