int min_race_time(std::vector<std::vector<int>>& tires, int changeTime, int numLaps) {
    int n = tires.size();
    std::vector<int> times(n);
    for (int i = 0; i < n; ++i)
        times[i] = tires[i][0] + (numLaps - 1) * tires[i][1];
    int min_time = *std::min_element(times.begin(), times.end()) + (numLaps - 1) * changeTime;

    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            if (i != j)
                min_time = std::min(min_time, times[i] + times[j] - tires[i][0] + (numLaps - 2) * changeTime);
    return min_time;
}
```

