using namespace std;

int balancedString(string s) {
    int n = s.size();
    unordered_map<char, int> freq_map;
    for (char c : s)
        freq_map[c]++;

    int i = 0, result = n;
    for (int j = 0; j < n; j++) {
        freq_map[s[j]]--;
        while (i < n && freq_map['Q'] <= n / 4 && freq_map['W'] <= n / 4 && freq_map['E'] <= n / 4 && freq_map['R'] <= n / 4) {
            result = min(result, j - i + 1);
            freq_map[s[i]]++;
            i++;
        }
    }
    return result;
}
