#include <bitset>
#include <vector>

int movesToChessboard(std::vector<std::vector<int>>& board) {
  int N = board.size();
  std::bitset<30> row, col;

  for (int i = 0; i < N; ++i)
    for (int j = 0; j < N; ++j)
      if (board[0][0] ^ board[i][0] ^ board[0][j] ^ board[i][j])
        return -1;

  for (int i = 0; i < N; ++i) {
    row.flip(i);
    col.flip(i);
  }

  int c = board[0] & col;
  int d = row.count() - row.count() & col;
  int max_count = max(c, d);

  if (max_count == N) return 0;

  if (N & 1) return max_count & 1 ? max_count / 2 : max_count / 2 + 1;
  else return max_count / 2;
}
```

1. Iterate through the board and check if swapping rows or columns can transform it into a chessboard by checking if the XOR of the first cell in each row and column, as well as the XOR with the current cell, is zero. If any of these XOR checks return a non-zero result, return -1 as it is impossible to transform the board into a chessboard.

