std::vector<int> assignTasks(std::vector<int>& servers, std::vector<int>& tasks) {
    int n = servers.size(), m = tasks.size();
    std::vector<int> ans(m);
    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, std::greater<std::pair<int, int>>> freeServers;

    for (int i = 0; i < n; ++i) {
        freeServers.push({servers[i], i});
    }

    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, std::greater<std::pair<int, int>>> busyServers;
    int currentTask = 0;

    while (currentTask < m) {
        while (!busyServers.empty() && busyServers.top().first <= currentTask) {
            freeServers.push({servers[busyServers.top().second], busyServers.top().second});
            busyServers.pop();
        }

        while (!freeServers.empty() && currentTask < m) {
            ans[currentTask] = freeServers.top().second;
            busyServers.push({currentTask + tasks[currentTask], freeServers.top().second});
            freeServers.pop();
            currentTask++;
        }

        if(freeServers.empty()) {
            currentTask = busyServers.top().first;
        }
    }

    return ans;
}
```

