#include <queue>
#include <vector>
using namespace std;

int minTime(vector<vector<int>>& grid) {
    int m = grid.size(), n = grid[0].size();
    vector<vector<int>> visited(m, vector<int>(n, 1000000));

    const int dx[] = {-1, 0, 1, 0};
    const int dy[] = {0, 1, 0, -1};

    visited[0][0] = 0;

    queue<pair<int, int>> q;
    q.push({0, 0});

    while (!q.empty()) {
        auto [x, y] = q.front();
        q.pop();

        for (int i = 0; i < 4; i++) {
            int nx = x + dx[i];
            int ny = y + dy[i];

            if (nx >= 0 && nx < m && ny >= 0 && ny < n) {
                int t = max(grid[nx][ny], visited[x][y] + 1);
                if (visited[nx][ny] > t) {
                    visited[nx][ny] = t;
                    q.push({nx, ny});
                }
            }
        }
    }

    return visited[m - 1][n - 1] == 1000000 ? -1 : visited[m - 1][n - 1];
}
```

