#include <algorithm>
#include <vector>
#include <string>

int min_minutes(std::string s, int k) {
    int n = s.length();
    std::vector<int> left_counts(3, 0), right_counts(3, 0);
    for (char c : s) right_counts[c - 'a']++;

    int ans = n, total = 0;
    while (true) {
        int l = 0, r = n - 1;
        while (l < r && left_counts[s[l] - 'a'] < k && right_counts[s[r] - 'a'] < k) {
            int need_left = std::max(0, k - left_counts[s[l] - 'a']);
            int need_right = std::max(0, k - right_counts[s[r] - 'a']);
            if (need_left <= need_right) {
                total += need_left;
                l++;
                left_counts[s[l] - 'a']++;
                right_counts[s[l] - 'a']--;
            } else {
                total += need_right;
                r--;
                right_counts[s[r] - 'a']--;
                left_counts[s[r] - 'a']++;
            }
        }
        ans = std::min(ans, total);
        if (l + 1 < s.length()) {
            total -= left_counts[s[l] - 'a'];
            left_counts[s[l] - 'a']--;
            right_counts[s[l + 1] - 'a']++;
            l++;
        } else break;
    }
    if(left_counts[0] >= k && left_counts[1] >= k && left_counts[2] >= k) return ans;
    return -1;
}
```

