vector<int> decrypt(vector<int>& code, int k) {
    int n = code.size();
    vector<int> result(n);
    if (k == 0) return vector<int>(n, 0);

    for (int i = 0; i < n; i++) {
        int sum = 0;
        for (int j = 1; j <= abs(k); j++) {
            sum += k > 0 ? code[(i + j) % n] : code[(i - j + n) % n];
        }
        result[i] = sum;
    }
    return result;
}
```

