#include <vector>
#include <set>
#include <utility>
using namespace std;

vector<int> traverseMatrix(vector<vector<int>>& grid, const vector<int>& queries, int m, int n) {
    vector<int> dx = {-1, 0, 1, 0};
    vector<int> dy = {0, 1, 0, -1};
    vector<int> answer(queries.size(), 0);

    for (int k = 0; k < queries.size(); ++k) {
        int q = queries[k];
        int points = 0;
        set<pair<int, int>> visited;

        function<void(int, int)> dfs = [&](int x, int y) {
            if (visited.find({x, y}) == visited.end() && grid[x][y] < q) {
                visited.insert({x, y});
                points++;
                for (int i = 0; i < 4; ++i) {
                    int nx = x + dx[i], ny = y + dy[i];
                    if (nx >= 0 && nx < m && ny >= 0 && ny < n) {
                        dfs(nx, ny);
                    }
                }
            }
        };

        dfs(0, 0);
        answer[k] = points;
    }

    return answer;
}

vector<int> maxPoints(vector<vector<int>>& grid, vector<int>& queries) {
    int m = grid.size();
    int n = grid[0].size();
    return traverseMatrix(grid, queries, m, n);
}
