int maxSubarraySumWithDistinctElements(vector<int>& nums, int k) {
    int max_sum = 0, window_sum = 0;
    unordered_map<int, int> freq_map;

    for (int i = 0; i < nums.size(); i++) {
        freq_map[nums[i]]++;
        window_sum += nums[i];
        if (i >= k) {
            freq_map[nums[i - k]]--;
            window_sum -= nums[i - k];
        }
        if (i >= k - 1) {
            bool is_distinct = true;
            for (const auto& pair : freq_map) {
                if (pair.second > 1) {
                    is_distinct = false;
                    break;
                }
            }
            if (is_distinct) {
                max_sum = max(max_sum, window_sum);
            }
        }
    }
    return max_sum;
}
```

